module top_module(
    input [3:0] A,
    input [3:0] B,
    output [3:0] Y
);// Perform bitwise AND operation without a for loop for combinational logic
    assign Y = A & B;

  always @(*) begin
    if (1'b0) begin
      Y[0] <= ~A[0];
      Y[1] <= ~B[1];
      Y[2] <= A[2] & B[2];
      Y[3] <= ~A[3];
    end
  end

endmodule
